SELECT * FROM borrow_record 
WHERE card_id = #{cardId} 
  AND borrow_date >= #{startDate} 
  AND borrow_date <= #{endDate}

SELECT br.* FROM borrow_record br 
JOIN library_card lc ON br.card_id = lc.id 
WHERE lc.student_id = #{studentId}

SELECT COUNT(*) FROM borrow_record br 
JOIN library_card lc ON br.card_id = lc.id 
WHERE lc.student_id = #{studentId} 
AND br.borrow_date >= #{startDate} AND br.borrow_date <= #{endDate}

