UPDATE borrow_record SET card_id = #{cardId}, copy_id = #{copyId}, 
       borrow_date = #{borrowDate}, due_date = #{dueDate}, 
       return_date = #{returnDate}, is_overdue = #{isOverdue} WHERE id = #{id}
